import{_ as t,c as d,o,ag as a}from"./chunks/framework.Bw-5EFTY.js";const h=JSON.parse('{"title":"DAG Core Specification","description":"","frontmatter":{},"headers":[],"relativePath":"packages/dag-core/docs/SPEC.md","filePath":"packages/dag-core/docs/SPEC.md"}'),c={name:"packages/dag-core/docs/SPEC.md"};function r(i,e,n,s,l,p){return o(),d("div",null,e[0]||(e[0]=[a(`<h1 id="dag-core-specification" tabindex="-1">DAG Core Specification <a class="header-anchor" href="#dag-core-specification" aria-label="Permalink to &quot;DAG Core Specification&quot;">​</a></h1><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p><code>@robota-sdk/dag-core</code> is the single source of truth (SSOT) for all DAG domain contracts, state rules, and validation logic in the Robota monorepo. It owns the canonical type definitions for DAG definitions, runs, tasks, ports, nodes, edges, errors, and state machines. Every other <code>dag-*</code> package depends on <code>dag-core</code> and must import its contracts from this package rather than re-declaring them. This package contains no infrastructure adapters or runtime orchestration logic; it defines what the DAG domain looks like, not how it executes at scale.</p><h2 id="boundaries" tabindex="-1">Boundaries <a class="header-anchor" href="#boundaries" aria-label="Permalink to &quot;Boundaries&quot;">​</a></h2><ul><li><strong>No infrastructure adapters.</strong> Storage, queue, and lease implementations belong to consumer packages. <code>dag-core</code> defines only the port interfaces (<code>IStoragePort</code>, <code>IQueuePort</code>, <code>ILeasePort</code>, <code>IClockPort</code>, <code>ITaskExecutorPort</code>).</li><li><strong>No orchestration runtime.</strong> DAG scheduling, worker polling, and run coordination belong to runtime and orchestration packages.</li><li><strong>No node implementations.</strong> Concrete node types belong to node implementation packages.</li><li><strong>No node authoring infrastructure.</strong> Base classes (<code>AbstractNodeDefinition</code>), accessors (<code>NodeIoAccessor</code>), registries, lifecycle wrappers, and value objects (<code>MediaReference</code>) belong to a dedicated node authoring package. <code>dag-core</code> defines the interfaces they implement but does not own the implementations.</li><li><strong>No projection or read models.</strong> Event-sourced projections belong to projection packages.</li><li><strong>No API layer.</strong> HTTP/REST composition belongs to API packages.</li><li><strong>No designer UI.</strong> Visual graph editing belongs to designer packages.</li><li><strong>Contract behavior must be deterministic and fail-fast.</strong> No fallback logic.</li></ul><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><h3 id="layer-structure" tabindex="-1">Layer Structure <a class="header-anchor" href="#layer-structure" aria-label="Permalink to &quot;Layer Structure&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>dag-core/</span></span>
<span class="line"><span>  src/</span></span>
<span class="line"><span>    types/           -- Domain type definitions (SSOT contracts)</span></span>
<span class="line"><span>    interfaces/      -- Port interfaces for infrastructure boundaries</span></span>
<span class="line"><span>    constants/       -- Status enums, event name constants</span></span>
<span class="line"><span>    state-machines/  -- DagRun and TaskRun finite state machines</span></span>
<span class="line"><span>    lifecycle/       -- Node lifecycle runner, cost policy evaluator, task executor port</span></span>
<span class="line"><span>    services/        -- Domain services (validation, definition mgmt, cost policy)</span></span>
<span class="line"><span>    registry/        -- (emptied — extracted to node authoring package)</span></span>
<span class="line"><span>    schemas/         -- (emptied — extracted to node authoring package)</span></span>
<span class="line"><span>    value-objects/   -- (emptied — extracted to node authoring package)</span></span>
<span class="line"><span>    utils/           -- Error builder helpers</span></span>
<span class="line"><span>    testing/         -- (emptied — extracted to dag-adapters-local package)</span></span>
<span class="line"><span>    __tests__/       -- Unit tests</span></span></code></pre></div><h3 id="design-patterns" tabindex="-1">Design Patterns <a class="header-anchor" href="#design-patterns" aria-label="Permalink to &quot;Design Patterns&quot;">​</a></h3><ul><li><strong>Result pattern (<code>TResult&lt;T, E&gt;</code>)</strong>: All domain operations return discriminated unions (<code>{ ok: true; value: T } | { ok: false; error: E }</code>) instead of throwing exceptions. This enforces explicit error handling at every call site.</li><li><strong>Port/adapter (hexagonal)</strong>: Infrastructure concerns are defined as port interfaces (<code>IStoragePort</code>, <code>IQueuePort</code>, <code>ILeasePort</code>, <code>IClockPort</code>, <code>ITaskExecutorPort</code>). <code>dag-core</code> owns the ports; consumer packages provide adapters. In-memory adapters for test harnesses are provided by <code>@robota-sdk/dag-adapters-local</code>.</li><li><strong>Finite state machines</strong>: <code>DagRunStateMachine</code> and <code>TaskRunStateMachine</code> encode all legal state transitions as a lookup table. Invalid transitions return errors rather than silently succeeding. Terminal states (<code>success</code>, <code>failed</code>, <code>cancelled</code>) have no outgoing transitions except the explicit <code>RETRY</code> gate on <code>TaskRun.failed -&gt; queued</code>.</li><li><strong>Abstract template pattern</strong>: <code>AbstractNodeDefinition&lt;TSchema&gt;</code> provides a config-parsing template that delegates to <code>*WithConfig</code> methods, ensuring every lifecycle step receives a validated, typed config object. (Owned by node authoring package.)</li><li><strong>Value object</strong>: <code>MediaReference</code> is an immutable value object with factory methods (<code>fromAssetReference</code>, <code>fromBinary</code>, <code>fromCandidate</code>) and no public constructor. (Owned by node authoring package.)</li><li><strong>SSOT ownership</strong>: Every domain type is defined exactly once in this package. Other packages import from <code>@robota-sdk/dag-core</code> and never re-declare these contracts.</li></ul><h2 id="type-ownership" tabindex="-1">Type Ownership <a class="header-anchor" href="#type-ownership" aria-label="Permalink to &quot;Type Ownership&quot;">​</a></h2><p>All types below are the canonical SSOT definitions. Other <code>dag-*</code> packages must import them from <code>@robota-sdk/dag-core</code>.</p><table tabindex="0"><thead><tr><th>Type</th><th>Location</th><th>Purpose</th></tr></thead><tbody><tr><td><code>TDagDefinitionStatus</code></td><td><code>types/domain.ts</code></td><td>Definition lifecycle status: <code>draft</code>, <code>published</code>, <code>deprecated</code></td></tr><tr><td><code>TPortValueType</code></td><td><code>types/domain.ts</code></td><td>Port data types: <code>string</code>, <code>number</code>, <code>boolean</code>, <code>object</code>, <code>array</code>, <code>binary</code></td></tr><tr><td><code>TBinaryKind</code></td><td><code>types/domain.ts</code></td><td>Binary payload kind: <code>image</code>, <code>video</code>, <code>audio</code>, <code>file</code></td></tr><tr><td><code>TNodeConfigValue</code></td><td><code>types/domain.ts</code></td><td>Recursive config value type (primitives, objects, arrays)</td></tr><tr><td><code>TNodeConfigRecord</code></td><td><code>types/domain.ts</code></td><td>Node configuration record (alias for <code>INodeConfigObject</code>)</td></tr><tr><td><code>TAssetReference</code></td><td><code>types/domain.ts</code></td><td>Discriminated union for asset-by-id or asset-by-uri references</td></tr><tr><td><code>TDagRunStatus</code></td><td><code>types/domain.ts</code></td><td>DAG run states: <code>created</code>, <code>queued</code>, <code>running</code>, <code>success</code>, <code>failed</code>, <code>cancelled</code></td></tr><tr><td><code>TTaskRunStatus</code></td><td><code>types/domain.ts</code></td><td>Task run states: <code>created</code>, <code>queued</code>, <code>running</code>, <code>success</code>, <code>failed</code>, <code>upstream_failed</code>, <code>skipped</code>, <code>cancelled</code></td></tr><tr><td><code>TDagTriggerType</code></td><td><code>types/domain.ts</code></td><td>Trigger types: <code>manual</code>, <code>scheduled</code>, <code>api</code></td></tr><tr><td><code>IPortDefinition</code></td><td><code>types/domain.ts</code></td><td>Port schema (key, type, required, binary constraints, list constraints)</td></tr><tr><td><code>INodeManifest</code></td><td><code>types/domain.ts</code></td><td>Node registration manifest (type, display name, category, ports, config schema)</td></tr><tr><td><code>ICostPolicy</code></td><td><code>types/domain.ts</code></td><td>Run-level cost budget configuration (<code>runCreditLimit</code>, <code>costPolicyVersion</code>)</td></tr><tr><td><code>IDagNode</code></td><td><code>types/domain.ts</code></td><td>Node instance within a DAG definition</td></tr><tr><td><code>IEdgeBinding</code></td><td><code>types/domain.ts</code></td><td>Single output-to-input port binding on an edge</td></tr><tr><td><code>IDagEdgeDefinition</code></td><td><code>types/domain.ts</code></td><td>Edge connecting two nodes with bindings</td></tr><tr><td><code>IDagDefinition</code></td><td><code>types/domain.ts</code></td><td>Complete DAG definition (nodes, edges, cost policy, schemas)</td></tr><tr><td><code>IDagRun</code></td><td><code>types/domain.ts</code></td><td>DAG execution run record</td></tr><tr><td><code>ITaskRun</code></td><td><code>types/domain.ts</code></td><td>Individual task execution record within a DAG run</td></tr><tr><td><code>IExecutionPathSegment</code></td><td><code>types/domain.ts</code></td><td>Segment of the hierarchical execution path</td></tr><tr><td><code>TErrorCategory</code></td><td><code>types/error.ts</code></td><td>Error categories: <code>validation</code>, <code>state_transition</code>, <code>lease</code>, <code>dispatch</code>, <code>task_execution</code></td></tr><tr><td><code>IDagError</code></td><td><code>types/error.ts</code></td><td>Canonical error structure (code, category, message, retryable, context)</td></tr><tr><td><code>TResult&lt;T, E&gt;</code></td><td><code>types/result.ts</code></td><td>Discriminated union result type for all domain operations</td></tr><tr><td><code>INodeLifecycle</code></td><td><code>types/node-lifecycle.ts</code></td><td>Full node lifecycle interface (initialize, validateInput, estimateCost, execute, validateOutput, dispose)</td></tr><tr><td><code>INodeLifecycleFactory</code></td><td><code>types/node-lifecycle.ts</code></td><td>Factory interface for creating <code>INodeLifecycle</code> instances by node type</td></tr><tr><td><code>INodeManifestRegistry</code></td><td><code>types/node-lifecycle.ts</code></td><td>Registry interface for looking up node manifests</td></tr><tr><td><code>INodeTaskHandler</code></td><td><code>types/node-lifecycle.ts</code></td><td>Partial lifecycle handler (only <code>execute</code> is required)</td></tr><tr><td><code>INodeTaskHandlerRegistry</code></td><td><code>types/node-lifecycle.ts</code></td><td>Registry interface for looking up task handlers</td></tr><tr><td><code>IDagNodeDefinition</code></td><td><code>types/node-lifecycle.ts</code></td><td>Composite definition combining manifest fields with a task handler</td></tr><tr><td><code>INodeDefinitionAssembly</code></td><td><code>types/node-lifecycle.ts</code></td><td>Assembly result of manifests and handlers from node definitions</td></tr><tr><td><code>INodeExecutionContext</code></td><td><code>types/node-lifecycle.ts</code></td><td>Execution context passed to lifecycle methods</td></tr><tr><td><code>INodeExecutionResult</code></td><td><code>types/node-lifecycle.ts</code></td><td>Execution result with output payload and cost data</td></tr><tr><td><code>ICostEstimate</code></td><td><code>types/node-lifecycle.ts</code></td><td>Cost estimate returned from <code>estimateCost</code> (<code>estimatedCredits</code>, <code>details?</code>)</td></tr><tr><td><code>IRunCostPolicyEvaluator</code></td><td><code>types/node-lifecycle.ts</code></td><td>Interface for budget enforcement</td></tr><tr><td><code>TRunProgressEvent</code></td><td><code>types/run-progress.ts</code></td><td>Discriminated union of all run progress event types</td></tr><tr><td><code>IRunProgressEventReporter</code></td><td><code>types/run-progress.ts</code></td><td>Interface for publishing progress events</td></tr><tr><td><code>TPortValue</code></td><td><code>interfaces/ports.ts</code></td><td>Union of all port value types (primitives, binary, arrays, objects)</td></tr><tr><td><code>TPortPayload</code></td><td><code>interfaces/ports.ts</code></td><td>Key-value map of port values</td></tr><tr><td><code>IQueuePort</code></td><td><code>interfaces/ports.ts</code></td><td>Queue infrastructure port (enqueue, dequeue, ack, nack)</td></tr><tr><td><code>ILeasePort</code></td><td><code>interfaces/ports.ts</code></td><td>Lease infrastructure port (acquire, renew, release, get)</td></tr><tr><td><code>IStoragePort</code></td><td><code>interfaces/ports.ts</code></td><td>Storage infrastructure port (definitions, runs, tasks)</td></tr><tr><td><code>ITaskExecutorPort</code></td><td><code>interfaces/ports.ts</code></td><td>Task execution infrastructure port</td></tr><tr><td><code>IClockPort</code></td><td><code>interfaces/ports.ts</code></td><td>Clock infrastructure port (nowIso, nowEpochMs)</td></tr><tr><td><code>IQueueMessage</code></td><td><code>interfaces/ports.ts</code></td><td>Queue message structure</td></tr><tr><td><code>ITaskExecutionInput</code></td><td><code>interfaces/ports.ts</code></td><td>Input payload for task execution</td></tr><tr><td><code>TTaskExecutionResult</code></td><td><code>interfaces/ports.ts</code></td><td>Discriminated union result from task execution</td></tr></tbody></table><h2 id="public-api-surface" tabindex="-1">Public API Surface <a class="header-anchor" href="#public-api-surface" aria-label="Permalink to &quot;Public API Surface&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Export</th><th>Kind</th><th>Description</th></tr></thead><tbody><tr><td><code>DagRunStateMachine</code></td><td>Class</td><td>Static state machine for DAG run status transitions</td></tr><tr><td><code>TaskRunStateMachine</code></td><td>Class</td><td>Static state machine for task run status transitions</td></tr><tr><td><code>DagDefinitionValidator</code></td><td>Class</td><td>Validates <code>IDagDefinition</code> structure (graph acyclicity, port compatibility, binding integrity)</td></tr><tr><td><code>DagDefinitionService</code></td><td>Class</td><td>Domain service for DAG definition CRUD and publish lifecycle</td></tr><tr><td><code>TimeSemanticsService</code></td><td>Class</td><td>Resolves trigger type and logical date with UTC normalization</td></tr><tr><td><code>NodeLifecycleRunner</code></td><td>Class</td><td>Orchestrates the full node lifecycle sequence (init, validate, estimate, execute, validate output, dispose)</td></tr><tr><td><code>RunCostPolicyEvaluator</code></td><td>Class</td><td>Evaluates whether estimated cost fits within the run budget</td></tr><tr><td><code>MissingNodeLifecycleFactory</code></td><td>Class</td><td>Sentinel factory that always returns an error (used as default)</td></tr><tr><td><code>LifecycleTaskExecutorPort</code></td><td>Class</td><td><code>ITaskExecutorPort</code> adapter that delegates to <code>NodeLifecycleRunner</code></td></tr><tr><td><code>buildValidationError</code></td><td>Function</td><td>Error builder for <code>validation</code> category</td></tr><tr><td><code>buildDispatchError</code></td><td>Function</td><td>Error builder for <code>dispatch</code> category</td></tr><tr><td><code>buildLeaseError</code></td><td>Function</td><td>Error builder for <code>lease</code> category</td></tr><tr><td><code>buildTaskExecutionError</code></td><td>Function</td><td>Error builder for <code>task_execution</code> category</td></tr><tr><td><code>buildDagError</code></td><td>Function</td><td>Generic error builder for any category</td></tr><tr><td><code>buildListPortHandleKey</code></td><td>Function</td><td>Builds a list-port handle key string (e.g., <code>images[0]</code>)</td></tr><tr><td><code>parseListPortHandleKey</code></td><td>Function</td><td>Parses a list-port handle key back to port key and index</td></tr><tr><td><code>DAG_DEFINITION_STATUS</code></td><td>Constant</td><td>Definition status enum object</td></tr><tr><td><code>DAG_RUN_STATUS</code></td><td>Constant</td><td>DAG run status enum object</td></tr><tr><td><code>TASK_RUN_STATUS</code></td><td>Constant</td><td>Task run status enum object</td></tr><tr><td><code>RUN_EVENTS</code>, <code>TASK_EVENTS</code>, <code>WORKER_EVENTS</code>, <code>SCHEDULER_EVENTS</code></td><td>Constants</td><td>Domain event name constants</td></tr><tr><td><code>EXECUTION_PROGRESS_EVENTS</code>, <code>TASK_PROGRESS_EVENTS</code></td><td>Constants</td><td>Progress event name constants</td></tr><tr><td><code>RUN_EVENT_PREFIX</code>, <code>TASK_EVENT_PREFIX</code>, <code>WORKER_EVENT_PREFIX</code>, <code>SCHEDULER_EVENT_PREFIX</code>, <code>EXECUTION_EVENT_PREFIX</code></td><td>Constants</td><td>Event prefix strings</td></tr><tr><td><code>DAG_CORE_PACKAGE_NAME</code></td><td>Constant</td><td>Package name string <code>@robota-sdk/dag-core</code></td></tr></tbody></table><blockquote><p><strong>Note:</strong> 인메모리 포트 구현체들은 <code>@robota-sdk/dag-adapters-local</code> 패키지로 분리됨. <code>InMemoryStoragePort</code>, <code>InMemoryQueuePort</code>, <code>InMemoryLeasePort</code>, <code>FakeClockPort</code>, <code>SystemClockPort</code>, <code>MockTaskExecutorPort</code> 등은 해당 패키지에서 import.</p></blockquote><h2 id="extension-points" tabindex="-1">Extension Points <a class="header-anchor" href="#extension-points" aria-label="Permalink to &quot;Extension Points&quot;">​</a></h2><h3 id="abstractnodedefinition-tschema" tabindex="-1">AbstractNodeDefinition&lt;TSchema&gt; <a class="header-anchor" href="#abstractnodedefinition-tschema" aria-label="Permalink to &quot;AbstractNodeDefinition\\&lt;TSchema\\&gt;&quot;">​</a></h3><p>The primary extension point for node implementors. <code>dag-core</code> defines the <code>IDagNodeDefinition</code> and <code>INodeLifecycle</code> interfaces; the abstract base class and supporting infrastructure are owned by the node authoring package.</p><h3 id="port-interfaces" tabindex="-1">Port Interfaces <a class="header-anchor" href="#port-interfaces" aria-label="Permalink to &quot;Port Interfaces&quot;">​</a></h3><p>Consumer packages implement these interfaces to provide infrastructure:</p><ul><li><code>IStoragePort</code> -- persistence for definitions, runs, and tasks.</li><li><code>IQueuePort</code> -- message queue for task dispatch (enqueue, dequeue, ack, nack).</li><li><code>ILeasePort</code> -- distributed lease management (acquire, renew, release).</li><li><code>IClockPort</code> -- clock abstraction for deterministic time in tests.</li><li><code>ITaskExecutorPort</code> -- task execution delegation.</li></ul><h3 id="inodetaskhandler" tabindex="-1">INodeTaskHandler <a class="header-anchor" href="#inodetaskhandler" aria-label="Permalink to &quot;INodeTaskHandler&quot;">​</a></h3><p>A lighter alternative to full <code>INodeLifecycle</code>. Only <code>execute</code> is required; all other lifecycle methods are optional. The <code>RegisteredNodeLifecycle</code> wrapper fills in defaults and adds base port validation for handlers that omit <code>validateInput</code>/<code>validateOutput</code>.</p><h2 id="error-taxonomy" tabindex="-1">Error Taxonomy <a class="header-anchor" href="#error-taxonomy" aria-label="Permalink to &quot;Error Taxonomy&quot;">​</a></h2><h3 id="error-structure" tabindex="-1">Error Structure <a class="header-anchor" href="#error-structure" aria-label="Permalink to &quot;Error Structure&quot;">​</a></h3><p>All errors conform to <code>IDagError</code>:</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">interface</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> IDagError</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">    code</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">    category</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> TErrorCategory</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">    message</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">    retryable</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> boolean</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">    context</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">?:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Record</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">string</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> number</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> boolean</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="error-categories" tabindex="-1">Error Categories <a class="header-anchor" href="#error-categories" aria-label="Permalink to &quot;Error Categories&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Category</th><th>Description</th><th>Default Retryable</th></tr></thead><tbody><tr><td><code>validation</code></td><td>Schema, structure, or constraint violations</td><td><code>false</code></td></tr><tr><td><code>state_transition</code></td><td>Invalid state machine transitions</td><td><code>false</code></td></tr><tr><td><code>lease</code></td><td>Lease acquisition or renewal failures</td><td><code>false</code></td></tr><tr><td><code>dispatch</code></td><td>Task dispatch/queue failures</td><td><code>true</code></td></tr><tr><td><code>task_execution</code></td><td>Errors during node execution</td><td>varies</td></tr></tbody></table><h3 id="error-codes" tabindex="-1">Error Codes <a class="header-anchor" href="#error-codes" aria-label="Permalink to &quot;Error Codes&quot;">​</a></h3><p><strong>Validation errors</strong> (category: <code>validation</code>, retryable: <code>false</code>):</p><table tabindex="0"><thead><tr><th>Code</th><th>Source</th><th>Description</th></tr></thead><tbody><tr><td><code>DAG_VALIDATION_EMPTY_DAG_ID</code></td><td><code>DagDefinitionValidator</code></td><td>dagId is empty</td></tr><tr><td><code>DAG_VALIDATION_INVALID_VERSION</code></td><td><code>DagDefinitionValidator</code></td><td>version is not a positive integer</td></tr><tr><td><code>DAG_VALIDATION_EMPTY_NODES</code></td><td><code>DagDefinitionValidator</code></td><td>DAG has no nodes</td></tr><tr><td><code>DAG_VALIDATION_EMPTY_NODE_ID</code></td><td><code>DagDefinitionValidator</code></td><td>nodeId is empty</td></tr><tr><td><code>DAG_VALIDATION_DUPLICATE_NODE_ID</code></td><td><code>DagDefinitionValidator</code></td><td>duplicate nodeId</td></tr><tr><td><code>DAG_VALIDATION_NODE_TYPE_REMOVED</code></td><td><code>DagDefinitionValidator</code></td><td>deprecated node type used</td></tr><tr><td><code>DAG_VALIDATION_EMPTY_INPUT_KEY</code></td><td><code>DagDefinitionValidator</code></td><td>input port key is empty</td></tr><tr><td><code>DAG_VALIDATION_EMPTY_OUTPUT_KEY</code></td><td><code>DagDefinitionValidator</code></td><td>output port key is empty</td></tr><tr><td><code>DAG_VALIDATION_DUPLICATE_INPUT_KEY</code></td><td><code>DagDefinitionValidator</code></td><td>duplicate input port key within a node</td></tr><tr><td><code>DAG_VALIDATION_DUPLICATE_OUTPUT_KEY</code></td><td><code>DagDefinitionValidator</code></td><td>duplicate output port key within a node</td></tr><tr><td><code>DAG_VALIDATION_INVALID_INPUT_ORDER</code></td><td><code>DagDefinitionValidator</code></td><td>input port order is not a non-negative integer</td></tr><tr><td><code>DAG_VALIDATION_INVALID_OUTPUT_ORDER</code></td><td><code>DagDefinitionValidator</code></td><td>output port order is not a non-negative integer</td></tr><tr><td><code>DAG_VALIDATION_INVALID_INPUT_MIN_ITEMS</code></td><td><code>DagDefinitionValidator</code></td><td>input port minItems is invalid</td></tr><tr><td><code>DAG_VALIDATION_INVALID_INPUT_MAX_ITEMS</code></td><td><code>DagDefinitionValidator</code></td><td>input port maxItems is invalid</td></tr><tr><td><code>DAG_VALIDATION_INVALID_INPUT_ITEM_RANGE</code></td><td><code>DagDefinitionValidator</code></td><td>minItems exceeds maxItems</td></tr><tr><td><code>DAG_VALIDATION_EDGE_FROM_NOT_FOUND</code></td><td><code>DagDefinitionValidator</code></td><td>edge references nonexistent source node</td></tr><tr><td><code>DAG_VALIDATION_EDGE_TO_NOT_FOUND</code></td><td><code>DagDefinitionValidator</code></td><td>edge references nonexistent target node</td></tr><tr><td><code>DAG_VALIDATION_BINDING_REQUIRED</code></td><td><code>DagDefinitionValidator</code></td><td>edge has no bindings</td></tr><tr><td><code>DAG_VALIDATION_BINDING_OUTPUT_NOT_FOUND</code></td><td><code>DagDefinitionValidator</code></td><td>binding references nonexistent output port</td></tr><tr><td><code>DAG_VALIDATION_BINDING_INPUT_NOT_FOUND</code></td><td><code>DagDefinitionValidator</code></td><td>binding references nonexistent input port</td></tr><tr><td><code>DAG_VALIDATION_BINDING_INPUT_KEY_DUPLICATE</code></td><td><code>DagDefinitionValidator</code></td><td>multiple outputs map to same input in one edge</td></tr><tr><td><code>DAG_VALIDATION_BINDING_INPUT_KEY_CONFLICT</code></td><td><code>DagDefinitionValidator</code></td><td>multiple upstream edges map to same input</td></tr><tr><td><code>DAG_VALIDATION_BINDING_TYPE_MISMATCH</code></td><td><code>DagDefinitionValidator</code></td><td>output and input port types are incompatible</td></tr><tr><td><code>DAG_VALIDATION_CYCLE_DETECTED</code></td><td><code>DagDefinitionValidator</code></td><td>DAG contains a cycle</td></tr><tr><td><code>DAG_VALIDATION_INVALID_COST_LIMIT</code></td><td><code>DagDefinitionValidator</code></td><td>cost limit is not positive</td></tr><tr><td><code>DAG_VALIDATION_INVALID_COST_POLICY_VERSION</code></td><td><code>DagDefinitionValidator</code></td><td>cost policy version is not positive</td></tr><tr><td><code>DAG_VALIDATION_TEST_ENTRY_NODE_COUNT_INVALID</code></td><td><code>DagDefinitionValidator</code></td><td>test DAG has wrong entry node count</td></tr><tr><td><code>DAG_VALIDATION_TEST_ENTRY_NODE_TYPE_INVALID</code></td><td><code>DagDefinitionValidator</code></td><td>test DAG entry node is wrong type</td></tr><tr><td><code>DAG_VALIDATION_DUPLICATE_VERSION</code></td><td><code>DagDefinitionService</code></td><td>definition with same dagId and version already exists</td></tr><tr><td><code>DAG_VALIDATION_DEFINITION_NOT_FOUND</code></td><td><code>DagDefinitionService</code></td><td>definition does not exist</td></tr><tr><td><code>DAG_VALIDATION_UPDATE_ONLY_DRAFT</code></td><td><code>DagDefinitionService</code></td><td>only draft definitions can be updated</td></tr><tr><td><code>DAG_VALIDATION_PUBLISH_ONLY_DRAFT</code></td><td><code>DagDefinitionService</code></td><td>only draft definitions can be published</td></tr><tr><td><code>DAG_VALIDATION_MISSING_LOGICAL_DATE</code></td><td><code>TimeSemanticsService</code></td><td>scheduled trigger requires logicalDate</td></tr><tr><td><code>DAG_VALIDATION_INVALID_LOGICAL_DATE</code></td><td><code>TimeSemanticsService</code></td><td>logicalDate is not valid ISO-8601</td></tr><tr><td><code>DAG_VALIDATION_NODE_CONFIG_SCHEMA_INVALID</code></td><td>node definition base class</td><td>node config fails Zod schema parse</td></tr><tr><td><code>DAG_VALIDATION_NODE_INPUT_MISSING</code></td><td>node I/O accessor</td><td>required input key is missing</td></tr><tr><td><code>DAG_VALIDATION_NODE_INPUT_TYPE_MISMATCH</code></td><td>node I/O accessor, lifecycle wrapper</td><td>input value type does not match port type</td></tr><tr><td><code>DAG_VALIDATION_NODE_INPUT_MIN_ITEMS_NOT_SATISFIED</code></td><td>node I/O accessor, lifecycle wrapper</td><td>list input has fewer items than minItems</td></tr><tr><td><code>DAG_VALIDATION_NODE_INPUT_MAX_ITEMS_EXCEEDED</code></td><td>node I/O accessor, lifecycle wrapper</td><td>list input has more items than maxItems</td></tr><tr><td><code>DAG_VALIDATION_NODE_REQUIRED_INPUT_MISSING</code></td><td>lifecycle wrapper</td><td>required input port value is missing</td></tr><tr><td><code>DAG_VALIDATION_NODE_REQUIRED_OUTPUT_MISSING</code></td><td>lifecycle wrapper</td><td>required output port value is missing</td></tr><tr><td><code>DAG_VALIDATION_NODE_OUTPUT_TYPE_MISMATCH</code></td><td>lifecycle wrapper</td><td>output value type does not match port type</td></tr><tr><td><code>DAG_VALIDATION_NODE_OUTPUT_MIN_ITEMS_NOT_SATISFIED</code></td><td>lifecycle wrapper</td><td>list output has fewer items than minItems</td></tr><tr><td><code>DAG_VALIDATION_NODE_OUTPUT_MAX_ITEMS_EXCEEDED</code></td><td>lifecycle wrapper</td><td>list output has more items than maxItems</td></tr><tr><td><code>DAG_VALIDATION_NODE_LIFECYCLE_NOT_REGISTERED</code></td><td>lifecycle factory, <code>MissingNodeLifecycleFactory</code></td><td>no lifecycle registered for node type</td></tr><tr><td><code>DAG_VALIDATION_NODE_DEFINITION_MISSING</code></td><td><code>LifecycleTaskExecutorPort</code></td><td>task execution input lacks nodeDefinition</td></tr><tr><td><code>DAG_VALIDATION_NODE_MANIFEST_NOT_FOUND</code></td><td><code>LifecycleTaskExecutorPort</code></td><td>no manifest registered for node type</td></tr><tr><td><code>DAG_VALIDATION_NEGATIVE_ESTIMATED_COST</code></td><td><code>RunCostPolicyEvaluator</code></td><td>estimated cost is negative</td></tr><tr><td><code>DAG_VALIDATION_COST_LIMIT_EXCEEDED</code></td><td><code>RunCostPolicyEvaluator</code></td><td>estimated run cost exceeds budget</td></tr><tr><td><code>DAG_VALIDATION_MEDIA_REFERENCE_INVALID</code></td><td>media reference value object</td><td>media reference structure is invalid</td></tr><tr><td><code>DAG_VALIDATION_MEDIA_REFERENCE_XOR_REQUIRED</code></td><td>media reference value object</td><td>exactly one of assetId or uri must be provided</td></tr><tr><td><code>DAG_VALIDATION_MEDIA_REFERENCE_TYPE_MISMATCH</code></td><td>media reference value object</td><td>referenceType does not match provided fields</td></tr></tbody></table><p><strong>State transition errors</strong> (category: <code>state_transition</code>, retryable: <code>false</code>):</p><table tabindex="0"><thead><tr><th>Code</th><th>Source</th><th>Description</th></tr></thead><tbody><tr><td><code>DAG_STATE_TRANSITION_INVALID</code></td><td><code>DagRunStateMachine</code>, <code>TaskRunStateMachine</code></td><td>attempted transition is not allowed</td></tr></tbody></table><p><strong>Task execution errors</strong> (category: <code>task_execution</code>, retryable: varies):</p><table tabindex="0"><thead><tr><th>Code</th><th>Source</th><th>Description</th></tr></thead><tbody><tr><td><code>DAG_TASK_EXECUTION_DISPOSE_FAILED</code></td><td><code>NodeLifecycleRunner</code></td><td>node dispose step failed after successful execution</td></tr></tbody></table><h2 id="state-lifecycle" tabindex="-1">State Lifecycle <a class="header-anchor" href="#state-lifecycle" aria-label="Permalink to &quot;State Lifecycle&quot;">​</a></h2><h3 id="dagrun-state-machine" tabindex="-1">DagRun State Machine <a class="header-anchor" href="#dagrun-state-machine" aria-label="Permalink to &quot;DagRun State Machine&quot;">​</a></h3><p>States: <code>created</code>, <code>queued</code>, <code>running</code>, <code>success</code>, <code>failed</code>, <code>cancelled</code></p><p>Terminal states: <code>success</code>, <code>failed</code>, <code>cancelled</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>created --QUEUE--&gt; queued --START--&gt; running --COMPLETE_SUCCESS--&gt; success</span></span>
<span class="line"><span>created --CANCEL--&gt; cancelled</span></span>
<span class="line"><span>queued --CANCEL--&gt; cancelled</span></span>
<span class="line"><span>running --COMPLETE_FAILURE--&gt; failed</span></span>
<span class="line"><span>running --CANCEL--&gt; cancelled</span></span></code></pre></div><p>Each transition emits a domain event with the <code>run.*</code> prefix (e.g., <code>run.queued</code>, <code>run.running</code>).</p><h3 id="taskrun-state-machine" tabindex="-1">TaskRun State Machine <a class="header-anchor" href="#taskrun-state-machine" aria-label="Permalink to &quot;TaskRun State Machine&quot;">​</a></h3><p>States: <code>created</code>, <code>queued</code>, <code>running</code>, <code>success</code>, <code>failed</code>, <code>upstream_failed</code>, <code>skipped</code>, <code>cancelled</code></p><p>Terminal states: <code>success</code>, <code>upstream_failed</code>, <code>skipped</code>, <code>cancelled</code></p><p><strong>Note</strong>: The <code>failed</code> state is NOT terminal — it has a single explicit policy gate: <code>RETRY</code> transitions back to <code>queued</code>. This is intentional: a failed task may be retried via the DLQ reinject mechanism. Consumer packages implementing run finalization must treat <code>failed</code> as terminal only when no remaining retries exist (i.e., a failed task with no remaining retries is effectively terminal for DAG completion evaluation).</p><h3 id="finalization-semantics" tabindex="-1">Finalization Semantics <a class="header-anchor" href="#finalization-semantics" aria-label="Permalink to &quot;Finalization Semantics&quot;">​</a></h3><p>For DAG run finalization (determining <code>success</code> vs <code>failed</code> outcome):</p><ul><li><code>failed</code> is the <strong>only</strong> task status that contributes to a <code>failed</code> DAG run outcome.</li><li><code>upstream_failed</code>, <code>skipped</code>, and <code>cancelled</code> are non-failure terminal states — they do not cause the DAG run to fail.</li><li>A DAG run is <code>success</code> when all tasks are in terminal states AND no task is <code>failed</code>.</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>created --QUEUE--&gt; queued --START--&gt; running --COMPLETE_SUCCESS--&gt; success</span></span>
<span class="line"><span>created --CANCEL--&gt; cancelled</span></span>
<span class="line"><span>queued --UPSTREAM_FAIL--&gt; upstream_failed</span></span>
<span class="line"><span>queued --SKIP--&gt; skipped</span></span>
<span class="line"><span>queued --CANCEL--&gt; cancelled</span></span>
<span class="line"><span>running --COMPLETE_FAILURE--&gt; failed</span></span>
<span class="line"><span>running --CANCEL--&gt; cancelled</span></span>
<span class="line"><span>failed --RETRY--&gt; queued</span></span></code></pre></div><p>Each transition emits a domain event with the <code>task.*</code> prefix (e.g., <code>task.queued</code>, <code>task.running</code>).</p><h2 id="event-architecture" tabindex="-1">Event Architecture <a class="header-anchor" href="#event-architecture" aria-label="Permalink to &quot;Event Architecture&quot;">​</a></h2><p><code>dag-core</code> defines event name constants but does not own an event bus or emitter. Event prefixes owned by this package:</p><table tabindex="0"><thead><tr><th>Prefix</th><th>Constant</th><th>Domain</th></tr></thead><tbody><tr><td><code>run</code></td><td><code>RUN_EVENT_PREFIX</code></td><td>DAG run state changes</td></tr><tr><td><code>task</code></td><td><code>TASK_EVENT_PREFIX</code></td><td>Task run state changes</td></tr><tr><td><code>worker</code></td><td><code>WORKER_EVENT_PREFIX</code></td><td>Worker lifecycle events</td></tr><tr><td><code>scheduler</code></td><td><code>SCHEDULER_EVENT_PREFIX</code></td><td>Scheduler evaluation events</td></tr><tr><td><code>execution</code></td><td><code>EXECUTION_EVENT_PREFIX</code></td><td>Execution progress events</td></tr></tbody></table><p>Progress event types are defined as <code>TRunProgressEvent</code> (discriminated union) with reporter interface <code>IRunProgressEventReporter</code>.</p><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Dependency</th><th>Purpose</th></tr></thead><tbody><tr><td><code>zod</code></td><td>Runtime schema validation for node configs and media references</td></tr><tr><td><code>zod-to-json-schema</code></td><td>Converts Zod schemas to JSON Schema 7 for manifest <code>configSchema</code></td></tr></tbody></table><p>No peer dependencies.</p><h2 id="class-contract-registry" tabindex="-1">Class Contract Registry <a class="header-anchor" href="#class-contract-registry" aria-label="Permalink to &quot;Class Contract Registry&quot;">​</a></h2><h3 id="internal-implementations" tabindex="-1">Internal Implementations <a class="header-anchor" href="#internal-implementations" aria-label="Permalink to &quot;Internal Implementations&quot;">​</a></h3><p>Implementations owned by this package:</p><table tabindex="0"><thead><tr><th>Interface</th><th>Implementor</th><th>Kind</th><th>Location</th></tr></thead><tbody><tr><td><code>INodeLifecycleFactory</code></td><td><code>MissingNodeLifecycleFactory</code></td><td>sentinel</td><td><code>src/lifecycle/node-lifecycle-runner.ts</code></td></tr><tr><td><code>IRunCostPolicyEvaluator</code></td><td><code>RunCostPolicyEvaluator</code></td><td>production</td><td><code>src/lifecycle/node-lifecycle-runner.ts</code></td></tr><tr><td><code>ITaskExecutorPort</code></td><td><code>LifecycleTaskExecutorPort</code></td><td>production</td><td><code>src/lifecycle/lifecycle-task-executor-port.ts</code></td></tr></tbody></table><blockquote><p><strong>Note:</strong> 인메모리 포트 어댑터(<code>InMemoryStoragePort</code>, <code>InMemoryQueuePort</code>, <code>InMemoryLeasePort</code>, <code>FakeClockPort</code>, <code>SystemClockPort</code>, <code>MockTaskExecutorPort</code>)는 <code>@robota-sdk/dag-adapters-local</code> 패키지로 분리됨. 해당 패키지의 SPEC.md 참조.</p></blockquote><h3 id="interfaces-designed-for-external-implementation" tabindex="-1">Interfaces Designed for External Implementation <a class="header-anchor" href="#interfaces-designed-for-external-implementation" aria-label="Permalink to &quot;Interfaces Designed for External Implementation&quot;">​</a></h3><p>The following interfaces are defined by <code>dag-core</code> and intended to be implemented by consumer packages. Each consumer package documents its own implementations in its SPEC.md.</p><table tabindex="0"><thead><tr><th>Interface</th><th>Expected Implementor Role</th></tr></thead><tbody><tr><td><code>IDagNodeDefinition</code></td><td>Node authoring packages (abstract base class)</td></tr><tr><td><code>INodeLifecycle</code></td><td>Node authoring packages (lifecycle wrapper)</td></tr><tr><td><code>INodeLifecycleFactory</code></td><td>Node authoring packages (factory from handler registry)</td></tr><tr><td><code>INodeManifestRegistry</code></td><td>Node authoring packages (manifest lookup)</td></tr><tr><td><code>INodeTaskHandlerRegistry</code></td><td>Node authoring packages (handler lookup)</td></tr><tr><td><code>IStoragePort</code></td><td>Persistence adapters (file, database)</td></tr><tr><td><code>IQueuePort</code></td><td>Message queue adapters</td></tr><tr><td><code>ILeasePort</code></td><td>Distributed lease adapters</td></tr><tr><td><code>IClockPort</code></td><td>Clock adapters (system, deterministic)</td></tr><tr><td><code>ITaskExecutorPort</code></td><td>Task execution adapters</td></tr></tbody></table><h2 id="test-strategy" tabindex="-1">Test Strategy <a class="header-anchor" href="#test-strategy" aria-label="Permalink to &quot;Test Strategy&quot;">​</a></h2><h3 id="current-test-files" tabindex="-1">Current Test Files <a class="header-anchor" href="#current-test-files" aria-label="Permalink to &quot;Current Test Files&quot;">​</a></h3><table tabindex="0"><thead><tr><th>File</th><th>Coverage</th></tr></thead><tbody><tr><td><code>__tests__/definition-service.test.ts</code></td><td><code>DagDefinitionValidator</code> (duplicate nodeId, cycle detection), <code>DagDefinitionService</code> (publish invalid, update non-draft)</td></tr><tr><td><code>__tests__/time-semantics.test.ts</code></td><td><code>TimeSemanticsService</code> (manual/api/scheduled triggers, UTC normalization, invalid date rejection)</td></tr></tbody></table><h3 id="coverage-gaps" tabindex="-1">Coverage Gaps <a class="header-anchor" href="#coverage-gaps" aria-label="Permalink to &quot;Coverage Gaps&quot;">​</a></h3><p>The following areas lack dedicated unit tests in this package:</p><ul><li><strong>DagRunStateMachine</strong> and <strong>TaskRunStateMachine</strong>: No tests for valid transitions, invalid transitions, or domain event emission. May be tested indirectly by consumer packages.</li><li><strong>NodeLifecycleRunner</strong>: No tests for the full lifecycle sequence (init, validate, estimate, budget check, execute, validate output, dispose) or cost policy evaluation.</li><li><strong>RunCostPolicyEvaluator</strong>: No tests for budget enforcement (negative cost, limit exceeded, within budget).</li><li><strong>LifecycleTaskExecutorPort</strong>: No tests for manifest lookup, node definition validation, or runner delegation.</li><li><strong>DagDefinitionValidator</strong>: Partial coverage. Missing tests for edge binding validation, port type compatibility, cost policy validation, list port handle resolution, and many specific validation codes.</li><li><strong>MediaReference</strong>, <strong>StaticNodeManifestRegistry</strong>, <strong>StaticNodeTaskHandlerRegistry</strong>: Owned by the node authoring package; tested there.</li><li><strong>In-memory testing ports</strong>: Extracted to <code>@robota-sdk/dag-adapters-local</code>. Tests belong there. That package also provides <code>FileStoragePort</code> (file-based <code>IStoragePort</code>) and <code>FileCostMetaStorage</code> (file-based <code>ICostMetaStoragePort</code> from <code>@robota-sdk/dag-cost</code>).</li></ul>`,73)]))}const g=t(c,[["render",r]]);export{h as __pageData,g as default};
